from sqlalchemy.orm import Mapped, mapped_columnfrom database.entity.BaseModel import BaseModelfrom typing import Optionalfrom sqlalchemy import TIMESTAMP,ARRAY,VARCHAR,TEXT,INTEGER,UUIDimport uuid,datetimefrom pgvector.sqlalchemy import VECTORfrom sqlalchemy.dialects.postgresql import JSONBclass PlatformUserProfileModel(BaseModel):    __tablename__ = 'platform_user_profile'    user_id: Mapped[uuid.UUID] = mapped_column(UUID, primary_key=True)    display_name: Mapped[str] = mapped_column(VARCHAR(100), comment="""显示名""")    title: Mapped[str] = mapped_column(VARCHAR(100), comment="""岗位，对应need表中的role_wanted""")    avatar_url: Mapped[Optional[str]] = mapped_column(TEXT)    bio: Mapped[Optional[str]] = mapped_column(TEXT, comment="""用于向量化的核心文本""")    city: Mapped[str] = mapped_column(VARCHAR(20), comment="""北京，上海，深圳，广州""")    skill_tags: Mapped[list] = mapped_column(ARRAY(TEXT))    industry_tags: Mapped[list] = mapped_column(ARRAY(TEXT))    completeness: Mapped[int] = mapped_column(INTEGER, comment="""档案完整度 0-100""")    updated_at: Mapped[datetime.datetime] = mapped_column(TIMESTAMP)    project_name: Mapped[Optional[str]] = mapped_column(VARCHAR(256))    funding_stage: Mapped[Optional[str]] = mapped_column(VARCHAR(128))    project_stage: Mapped[Optional[str]] = mapped_column(VARCHAR(128))    team_size: Mapped[Optional[str]] = mapped_column(VARCHAR(128), comment="""1人（单独创业）    2-5人6-20人20人以上""")    investment_tags: Mapped[Optional[str]] = mapped_column(TEXT)    need_tags: Mapped[Optional[list]] = mapped_column(ARRAY(TEXT))    work_type: Mapped[Optional[list]] = mapped_column(ARRAY(TEXT))    partner_match_at: Mapped[Optional[datetime.datetime]] = mapped_column(TIMESTAMP, comment="""生成比对结果时间""")    embedding_update_at: Mapped[Optional[datetime.datetime]] = mapped_column(TIMESTAMP)    profile_data: Mapped[Optional[str]] = mapped_column(JSONB)    embedding: Mapped[Optional[list]] = mapped_column(VECTOR)